   b.关闭文件：

   ~~~c++
   void close(); //close()是fstream、ifstream和ofstream对象的一个成员
   ~~~

   c.读取&写入示例代码：

   ~~~c++
   #include <fstream>
   #include <iostream>
   using namespace std;
   int main(){
       char data[105];
       //已写模式打开文件
       ofstream outfile;
       outfile.open("afile.dat");

       cout<<"Writing..."<<endl;
       cout<<"Name: ";
       cin.getline(data, 105);
       outfile<<data<<endl; //数据写入文件
       cout<<"Age: ";
       cin>>data;
       cin.ignore(); //ignore()函数会忽略之前读语句留下的多余字符。
       outfile<<data<<endl;
       outfile.close();
       //以读模式打开文件
       ifstream infile;
       infile.open("afile.dat");

       cout<<"Reading..."<<endl;
       infile>>data;
       cout<<data<<endl;
       infile>>data;
       cout<<data<<endl;
       infile.close();

       return 0;
   }
   ~~~



